// n8n Function node code
// Input: items[] containing either:
//  - a single item where item.json is the thread object { id, historyId, messages: [...] }
//  - or items where each item.json is a message object
//
// Output: items[] where each output item corresponds to an input "thread" and contains:
//  { threadId, consecutiveSentCount, lastClientReplyDate, sentMessageIdsAfterLastClientReply, totalMessages }

function getFromField(msg) {
  // Try common locations for 'From'
  if (msg.From) return msg.From;
  if (msg.payload && msg.payload.headers) {
    const hdr = msg.payload.headers.find(h => h.name && h.name.toLowerCase() === 'from');
    if (hdr) return hdr.value;
  }
  return null;
}

function normalizeSender(fromValue) {
  if (!fromValue) return '';
  return fromValue.toString().toLowerCase();
}

// helper to test whether sender is our account
const OUR_ADDRESS = 'mis.scaleupally'; // partial match; we'll use includes

const results = [];

if (items.length === 0) {
  return [];
}

// If first item has messages array, treat each such item as a thread
for (let rootItem of items) {
  const root = rootItem.json || {};
  let messages = [];

  if (Array.isArray(root.messages)) {
    messages = root.messages.slice(); // copy
  } else {
    // maybe each incoming n8n item is a message; gather them all into messages
    // fallback: if rootItem looks like a single message, treat items array as messages
    if (items.every(it => it.json && (it.json.id || it.json.internalDate))) {
      messages = items.map(it => it.json);
      // Ensure we only run once in this fallback
      // clear items so outer loop doesn't duplicate
      items = [];
    } else {
      // nothing to do
      messages = [];
    }
  }

  if (messages.length === 0) {
    // produce a minimal output
    results.push({
      json: {
        threadId: root.id || null,
        consecutiveSentCount: 0,
        lastClientReplyDate: null,
        sentMessageIdsAfterLastClientReply: [],
        totalMessages: 0
      }
    });
    continue;
  }

  // Normalize messages and ensure internalDate exists as number
  messages = messages.map(m => {
    const d = Number(m.internalDate) || (m.internalDate && Date.parse(m.internalDate)) || 0;
    return Object.assign({}, m, { _internalDateNum: d });
  });

  // Sort ascending by date (oldest first)
  messages.sort((a,b) => a._internalDateNum - b._internalDateNum);

  // Find index of last message that is NOT from our sender
  let lastClientIndex = -1;
  for (let i = messages.length - 1; i >= 0; i--) {
    const from = normalizeSender(getFromField(messages[i]));
    // consider it 'ours' if it contains our short address or full address; adjust as needed
    const isOurs = from.includes(OUR_ADDRESS) || from.includes('mis.scaleupally@') || from.includes('mis.scaleupally.gmail'); // relax matching
    if (!isOurs) {
      lastClientIndex = i;
      break;
    }
  }

  // If lastClientIndex == -1 => there is NO client message at all
  // We'll treat lastClientIndex = -1 and count from start the trailing 'ours' messages
  let consecutiveSentCount = 0;
  const sentMessageIdsAfter = [];

  // Count messages after lastClientIndex that are from us until a non-us appears (there won't be non-us after because lastClientIndex is the last non-us)
  for (let i = lastClientIndex + 1; i < messages.length; i++) {
    const from = normalizeSender(getFromField(messages[i]));
    const isOurs = from.includes(OUR_ADDRESS) || from.includes('mis.scaleupally@') || from.includes('mis.scaleupally.gmail');
    if (isOurs) {
      consecutiveSentCount++;
      sentMessageIdsAfter.push(messages[i].id || messages[i].messageId || null);
    } else {
      // If a non-our message appears after lastClientIndex (rare by definition), stop counting
      break;
    }
  }

  const lastClientDate = lastClientIndex >= 0 ? new Date(messages[lastClientIndex]._internalDateNum).toISOString() : null;

  results.push({
    json: {
      threadId: root.id || (messages[0] && messages[0].threadId) || null,
      historyId: root.historyId || null,
      consecutiveSentCount: consecutiveSentCount,
      lastClientReplyDate: lastClientDate,
      lastClientReplyMessageId: lastClientIndex >= 0 ? (messages[lastClientIndex].id || null) : null,
      sentMessageIdsAfterLastClientReply: sentMessageIdsAfter,
      totalMessages: messages.length
    }
  });
}

// Return results to n8n
return results;

// n8n Function node
// Input: items[] where each item.json contains at least:
//  - lastClientReplyDate  (ISO string or null)
//  - consecutiveSentCount (integer)  <-- your "follow_up counts"
// Output: items[] with json.followUpDue = true/false

// Configure thresholds (days) per follow_up count here:
const thresholds = {
  1: 2,   // last reply > 2 days  & follow_up == 1
  2: 3,   // last reply > 3 days  & follow_up == 2
  3: 3,   // last reply > 3 days  & follow_up == 3
  4: 3,   // (example) edit as needed
  5: 3,   // (example) edit as needed
  6: 3
};

// helper: compute age in days between now and a date string
function daysSince(isoDateString) {
  if (!isoDateString) return Infinity; // treat missing date as infinite age (or change to large number)
  const then = new Date(isoDateString).getTime();
  if (isNaN(then)) return Infinity;
  const now = Date.now();
  const ms = now - then;
  return ms / (1000 * 60 * 60 * 24);
}

const out = [];

for (let i = 0; i < items.length; i++) {
  const data = items[i].json || {};
  const lastClientReplyDate = data.lastClientReplyDate || null;
  const followUpCount = Number(data.consecutiveSentCount || 0);

  // default false
  let followUpDue = false;

  // Only evaluate if there is a rule for this followUpCount
  if (followUpCount > 0 && Object.prototype.hasOwnProperty.call(thresholds, followUpCount)) {
    const thresholdDays = Number(thresholds[followUpCount]);
    const ageDays = daysSince(lastClientReplyDate);

    // followUpDue if last reply is older than threshold and threshold > 0
    if (!isNaN(thresholdDays) && thresholdDays > 0 && ageDays > thresholdDays) {
      followUpDue = true;
    }
  } else {
    // optional: handle followUpCount == 0 or unmatched counts
    // keep followUpDue = false
  }

  out.push({
    json: {
      ...data,
      followUpDue,
      _followUpRuleApplied: followUpCount > 0 ? thresholds[followUpCount] ?? null : null,
      _daysSinceLastClientReply: lastClientReplyDate ? daysSince(lastClientReplyDate) : null
    }
  });
}

return out;

// Function: choose last external message id (reply target)
// Paste into n8n Function node. Edit ownEmails if you send from other aliases.

const ownEmails = [
  'mis.scaleupally@gmail.com', // change / add other aliases you send from (lowercase)
];

function extractEmail(fromField) {
  if (!fromField) return '';
  const s = String(fromField);
  const m = s.match(/<([^>]+)>/);
  if (m) return m[1].toLowerCase();
  const maybe = s.trim().toLowerCase();
  return (/\S+@\S+\.\S+/.test(maybe)) ? maybe : '';
}

const debug = { steps: [] };
let msgs = [];

// 1) Try to read thread from "Get a thread" node (use $node, not $())
try {
  debug.steps.push('trying $node["Get a thread"]');
  const getThreadNode = $node["Get a thread"];
  if (getThreadNode && getThreadNode.json && Array.isArray(getThreadNode.json.messages)) {
    msgs = getThreadNode.json.messages.slice();
    debug.steps.push('got messages from $node["Get a thread"] count=' + msgs.length);
  } else {
    debug.steps.push('$node["Get a thread"] present but no messages array');
  }
} catch (e) {
  debug.steps.push('error reading $node["Get a thread"]: ' + e.message);
}

// 2) Fallback to current input (if this Function receives the thread item)
if (!msgs.length) {
  try {
    debug.steps.push('falling back to $input.all()');
    const input = $input.all();
    if (input.length && input[0].json && Array.isArray(input[0].json.messages)) {
      msgs = input[0].json.messages.slice();
      debug.steps.push('took messages from input[0].json.messages count=' + msgs.length);
    } else if (input.length && input.every(it => it.json && (it.json.id || it.json.messageId))) {
      // maybe each item is already a message
      msgs = input.map(i => i.json).filter(Boolean);
      debug.steps.push('took messages from separate input items count=' + msgs.length);
    } else {
      debug.steps.push('no messages found in $input.all()');
    }
  } catch (e) {
    debug.steps.push('error accessing $input: ' + e.message);
  }
}

// If still no messages, return early with debug
if (!msgs || !msgs.length) {
  return [
    { json: { replyMessageId: null, replyToEmail: '', threadId: null, debug } }
  ];
}

// Normalize and sort (oldest -> newest)
msgs = msgs.map(m => {
  const internal = Number(m.internalDate || m.internal_date || m._dateNum || 0);
  return Object.assign({}, m, { _internalDateNum: internal });
});
msgs.sort((a,b) => (a._internalDateNum || 0) - (b._internalDateNum || 0));
debug.steps.push('sorted messages count=' + msgs.length);

// Walk from newest -> oldest and pick first message not from ownEmails
let chosen = null;
let chosenEmail = '';
for (let i = msgs.length - 1; i >= 0; i--) {
  const m = msgs[i];
  // try common "from" fields
  let fromField = m.from || m.From || m.originalSenderEmail || '';
  if (!fromField && m.payload && Array.isArray(m.payload.headers)) {
    const h = m.payload.headers.find(h => /from/i.test(h.name));
    if (h) fromField = h.value || '';
  }
  const email = extractEmail(fromField);
  debug.steps.push(`msg[${i}].id=${m.id||m.messageId||''} from="${fromField}" parsed="${email}"`);
  if (!email) continue;
  if (!ownEmails.includes(email)) { // external found
    chosen = m;
    chosenEmail = email;
    debug.steps.push('chosen external message id=' + (m.id||m.messageId));
    break;
  }
}

// fallback to last message if no external found
if (!chosen) {
  chosen = msgs[msgs.length - 1];
  let fromField = chosen.from || chosen.From || chosen.originalSenderEmail || '';
  if (!fromField && chosen.payload && Array.isArray(chosen.payload.headers)) {
    const h = chosen.payload.headers.find(h => /from/i.test(h.name));
    if (h) fromField = h.value || '';
  }
  chosenEmail = extractEmail(fromField);
  debug.steps.push('no external found - fallback chosen id=' + (chosen.id||chosen.messageId) + ' from=' + fromField);
}

const replyMessageId = chosen ? (chosen.id || chosen.messageId || null) : null;
const threadId = chosen ? (chosen.threadId || msgs[0].threadId || null) : (msgs[0].threadId || null);

return [
  {
    json: {
      replyMessageId,
      replyToEmail: chosenEmail || '',
      threadId,
      debug
    }
  }
];

